'use client';

import { use } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { ArrowLeft, Calendar, Clock } from 'lucide-react';
import ScrollReveal from '@/components/ScrollReveal';
import { BLOG_POSTS } from '@/lib/constants';

export default function BlogPostPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = use(params);
  const post = BLOG_POSTS.find((p) => p.slug === slug);

  if (!post) {
    return (
      <section className="bg-bg pt-40 pb-24 px-6">
        <div className="max-w-3xl mx-auto text-center">
          <h1 className="font-serif text-4xl text-text-primary mb-4">
            Post Not Found
          </h1>
          <p className="text-text-secondary mb-8">
            The article you are looking for does not exist.
          </p>
          <Link href="/blog" className="btn-primary inline-flex items-center gap-2 text-sm">
            <ArrowLeft size={16} />
            Back to Blog
          </Link>
        </div>
      </section>
    );
  }

  /* Parse content into structured blocks */
  const contentBlocks = parseContent(post.content);

  return (
    <>
      {/* Hero - Full width image with overlay */}
      <section className="relative h-[50vh] min-h-[400px] overflow-hidden">
        <Image
          src={post.image}
          alt={post.title}
          fill
          className="object-cover"
          sizes="100vw"
          priority
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-black/20" />

        <div className="absolute inset-0 flex items-end">
          <div className="max-w-3xl mx-auto w-full px-6 pb-12">
            <span className="text-gold text-[11px] tracking-[0.15em] uppercase font-medium mb-4 block">
              {post.category}
            </span>
            <h1 className="font-serif text-3xl md:text-5xl text-white mb-4 leading-tight">
              {post.title}
            </h1>
            <div className="flex items-center gap-5">
              <span className="flex items-center gap-1.5 text-white/60 text-sm">
                <Calendar size={14} />
                {new Date(post.date).toLocaleDateString('en-US', {
                  month: 'long',
                  day: 'numeric',
                  year: 'numeric',
                })}
              </span>
              <span className="flex items-center gap-1.5 text-white/60 text-sm">
                <Clock size={14} />
                {post.readTime}
              </span>
            </div>
          </div>
        </div>
      </section>

      {/* Article Content */}
      <section className="bg-bg-white py-16 px-6">
        <div className="max-w-3xl mx-auto">
          <ScrollReveal>
            {/* Back link */}
            <Link
              href="/blog"
              className="inline-flex items-center gap-2 text-text-tertiary text-sm mb-10 hover:text-gold transition-colors duration-300"
            >
              <ArrowLeft size={14} />
              Back to Blog
            </Link>

            {/* Article body */}
            <article className="space-y-6">
              {contentBlocks.map((block, i) => {
                if (block.type === 'heading') {
                  return (
                    <h2
                      key={i}
                      className="font-serif text-2xl text-text-primary mt-10 mb-4"
                    >
                      {block.text}
                    </h2>
                  );
                }
                if (block.type === 'list') {
                  return (
                    <ul key={i} className="space-y-2 pl-1">
                      {block.items!.map((item, j) => (
                        <li
                          key={j}
                          className="flex items-start gap-3 text-text-secondary leading-relaxed"
                        >
                          <span className="w-1.5 h-1.5 rounded-full bg-gold mt-2.5 flex-shrink-0" />
                          {item}
                        </li>
                      ))}
                    </ul>
                  );
                }
                return (
                  <p
                    key={i}
                    className="text-text-secondary leading-relaxed"
                  >
                    {block.text}
                  </p>
                );
              })}
            </article>

            {/* Tags */}
            <div className="mt-12 pt-8 border-t border-border">
              <div className="flex flex-wrap gap-2">
                {post.tags.map((tag) => (
                  <span
                    key={tag}
                    className="px-3 py-1.5 rounded-full bg-bg-light text-text-tertiary text-[11px] tracking-wider uppercase"
                  >
                    {tag}
                  </span>
                ))}
              </div>
            </div>
          </ScrollReveal>
        </div>
      </section>
    </>
  );
}

/* Content parser */
type ContentBlock =
  | { type: 'heading'; text: string }
  | { type: 'paragraph'; text: string }
  | { type: 'list'; items: string[] };

function parseContent(content: string): ContentBlock[] {
  const lines = content.split('\n');
  const blocks: ContentBlock[] = [];
  let listBuffer: string[] = [];

  const flushList = () => {
    if (listBuffer.length > 0) {
      blocks.push({ type: 'list', items: [...listBuffer] });
      listBuffer = [];
    }
  };

  for (const line of lines) {
    const trimmed = line.trim();

    if (!trimmed) {
      flushList();
      continue;
    }

    if (trimmed.startsWith('## ')) {
      flushList();
      blocks.push({ type: 'heading', text: trimmed.replace('## ', '') });
    } else if (trimmed.startsWith('- ')) {
      listBuffer.push(trimmed.replace('- ', ''));
    } else {
      flushList();
      blocks.push({ type: 'paragraph', text: trimmed });
    }
  }

  flushList();
  return blocks;
}
